namespace sv_13062f946e89423ea663dcba717e64d6.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_13062f946e89423ea663dcba717e64d6.Client.Models;

namespace sv_13062f946e89423ea663dcba717e64d6.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_13062f946e89423ea663dcba717e64d6.Client.Models;
using sv_13062f946e89423ea663dcba717e64d6.Client.Services;

namespace sv_13062f946e89423ea663dcba717e64d6.Services;

public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 24, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.Zero) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTimeOffset(2026, 5, 23, 11, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 25, 7, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 25, 11, 45, 0, TimeSpan.Zero) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTimeOffset(2026, 5, 26, 0, 30, 0, TimeSpan.Zero) },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_13062f946e89423ea663dcba717e64d6.Client.Models;

namespace sv_13062f946e89423ea663dcba717e64d6.Client.Services;

public sealed class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

